module RefModule(
  input reset,
  input clk,
  output rst_sync
);parameter n = 2; // number of cycles that reset must be stable

reg [1:0] unused_sync_reset; // two-stage synchronizer

always @(posedge clk) begin
  unused_sync_reset[0] <= reset;
  unused_sync_reset[1] <= unused_sync_reset[0];
end

assign rst_sync = unused_sync_reset[1];

endmodule
